function preFilter(query) {
  const q = query.toLowerCase();
  const lines = ALL_BIZ.split('\n').filter(l => l.trim());

  // Detect location hints
  const locHints = [];
  for (const [key, vals] of Object.entries(CITY_MAP)) {
    if (q.includes(key)) locHints.push(...vals);
  }
  for (const [key, vals] of Object.entries(PROVINCE_MAP)) {
    if (q.includes(key)) locHints.push(...vals);
  }

  // Detect activity hints
  const actHints = [];
  for (const [key, terms] of Object.entries(ACTIVITY_SYNONYMS)) {
    if (terms.some(t => q.includes(t))) actHints.push(...terms);
  }
  // Also raw query words > 3 chars
  const qWords = q.split(/\s+/).filter(w => w.length > 3 && !['with','near','around','from','into','that','this','have','been'].includes(w));

  const hasLocation = locHints.length > 0;

  const scored = lines.map(line => {
    const low = line.toLowerCase();
    let score = 0;

    if (low.includes('pass_offer')) score += 8;

    if (hasLocation) {
      if (locHints.some(h => low.includes(h))) score += 25;
      else score -= 10;
    }

    if (actHints.length > 0 && actHints.some(h => low.includes(h))) score += 15;
    qWords.forEach(w => { if (low.includes(w)) score += 4; });

    return { line, score };
  });

  // Always include relevant PASS_OFFERs, fill rest with top scorers
  const passes = scored.filter(b => b.line.includes('PASS_OFFER') && b.score > 0)
                        .sort((a,b) => b.score - a.score);
  const others = scored.filter(b => !b.line.includes('PASS_OFFER'))
                        .sort((a,b) => b.score - a.score)
                        .slice(0, 80);

  const seen = new Set();
  const result = [...passes, ...others].filter(b => {
    if (seen.has(b.line)) return false;
    seen.add(b.line); return true;
  }).slice(0, 100);

  return result.map(b => b.line).join('\n');
}


function post(url, data, auth) {
  return new Promise(function(resolve, reject) {
    var body = JSON.stringify(data);
    var u = new URL(url);
    var req = https.request({
      hostname: u.hostname, path: u.pathname, method: 'POST',
      headers: {'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(body), 'Authorization': auth}
    }, function(res) {
      var d = '';
      res.on('data', function(c) { d += c; });
      res.on('end', function() {
        try { resolve({status: res.statusCode, body: JSON.parse(d)}); }
        catch(e) { reject(new Error('Parse error')); }
      });
    });
    req.on('error', reject);
    req.write(body); req.end();
  });
}

module.exports = async function(req, res) {
  res.setHeader('Access-Control-Allow-Origin', '*');
  res.setHeader('Access-Control-Allow-Methods', 'POST, OPTIONS');
  res.setHeader('Access-Control-Allow-Headers', 'Content-Type');
  if (req.method === 'OPTIONS') return res.status(200).end();
  if (req.method !== 'POST') return res.status(405).json({error: 'Method not allowed'});

  var OPENAI = process.env.OPENAI_API_KEY;
  if (!OPENAI) return res.status(500).json({error: 'OPENAI_API_KEY not set'});

  var query = (req.body || {}).query || '';
  if (!query) return res.status(400).json({error: 'No query'});

  try {
    var r = await post('https://api.openai.com/v1/chat/completions', {
      model: 'gpt-4o-mini',
      max_tokens: 600,
      temperature: 0.1,
      messages: [
        {
          role: 'system',
          content: 'You are a search assistant for BUGMe.Travel, a road trip adventure platform covering ONLY Canada and USA.\n\nGEOGRAPHY RULES (most important):\n- If the query asks for a location OUTSIDE Canada or USA (e.g. Africa, Europe, Asia, Australia, South America, Mexico), return an empty array [].\n- If the query names a specific Canadian province or city, ONLY return operators in that province/city. Do not return operators from other provinces or the USA.\n- If the query names a specific US state or city, ONLY return operators in that state/city.\n- If no location is specified, return the best activity matches from anywhere in Canada/USA.\n- NEVER return operators that are geographically wrong for the query.\n\nACTIVITY RULES:\n- Only return operators that genuinely offer the requested activity. Do not stretch or guess.\n- If no operators match both location AND activity, return [].\n\nPASS OFFER RULE:\n- Operators marked PASS_OFFER have a Road Trip Pass discount. Prioritize them first if they genuinely match.\n\nLocation codes: BC=British Columbia, AB=Alberta, ON=Ontario, QC=Quebec, SK=Saskatchewan, MB=Manitoba.\n\nReturn ONLY a valid JSON array, no other text: [{"id": 123, "reason": "one friendly sentence"}]\nIf nothing matches, return exactly: []'
        },
        {
          role: 'user',
          content: 'Search: "' + query + '"\n\nOperators:\n' + preFilter(query)
        }
      ]
    }, 'Bearer ' + OPENAI);

    if (r.status !== 200) return res.status(500).json({error: r.body.error ? r.body.error.message : 'OpenAI error'});

    var text = (r.body.choices[0].message.content || '[]').replace(/```json|```/g, '').trim();
    return res.status(200).json({text: text});

  } catch(e) {
    return res.status(500).json({error: e.message});
  }
};
